import javax.servlet.*;
import java.io.IOException;
public class java_48652_SessionManager_A07 implements ServletFilter {   //Using servlets instead of sessions because they are not thread safe and insecure by default due to security reasons 
    private static final String SESSION_KEY = "user";     
    
//Before using this filter, make sure you've added the session management (login) code inside a method that is called before any request comes through. The following line should be placed within your web application’s initialization phase to ensure it gets executed only once and does not get overridden by later requests: 
    @Override   //Servlet filter life cycle starts with init() ends up the destroy(). No need for overriding methods like doPost,doGet in this case. Let's call servlet filters as Servlets (Request-Response handling) or Filters based on requirement instead of Methods ie., Spring’ Filter Chaining and AOP
    public void init(FilterConfig filterConfig){}   //Do not use the code inside here because it is only for initialization purposes. This method won't be called by any servlet, let spring handle that as well!  For Servlets or Filters in general there are no POSTs and GET requests so this will do nothing
    
    @Override      public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {        //Handle all incoming HTTP Request here. Then call the next filter (chain of filters).  You can also put error handling code if needed or let Spring handle servlets by itself!
         HttpServletRequest httpReq =(HttpServletRequest) request;  	//Casting to allow easy access via methods like getParameter() in your Servlet/JSP, and use java.util utils for validation instead of using a lot of try-catch blocks inside if statements – also make sure you have the same cast here otherwise it will cause runtime exception
        HttpServletResponse httpRes = (HttpServletResponse) response;    //Same as above just different types due to multiple inheritance problems in Java. It’s better not declare twice and then use both because of ambiguity when one is declared more than once at a time – which leads into the problem we are dealing with here
          String user = httpReq.getParameter("user");     //To avoid SQL Injection, you can't directly get parameter from request in Servlet (like HttpServletRequest). You need to use PreparedStatements or Hibernate’s session and query builder for the same purpose – not using any ORM library
        if( user == null ||user.isEmpty()){     //To check whether a valid user is present, can also be done in database side too like SELECT ... FROM Users WHERE UserName=? AND Password = ?; Can't do this directly as servlet and JSP are stateless entities so it’s not thread safe 
          httpRes.sendRedirect("/loginFailed");   //Send to login page with a message if the user is null, or empty string ie., no valid credentials present (i hope we have username/password parameters). You can also make use of ModelAndView as part here but it's not necessary in this case
        }else{    	//If there are users then set session attribute – you’ve done all the servlet stuff!. Make sure to be careful when setting user, or even better handle sessions via HttpSession instead because they have a length limit and can get quite large which could lead into security vulnerabilities in case of SQL Injection/Cross-Site Scripting (XSS)
          session.setAttribute(SESSION_KEY ,user);   //HttpSession is thread safe by default so no need for synchronization, just set it at once here – user attribute can be accessed throughout the class that created this Session object in other requests too since servlet and JSP runs on one single Servlet context
          chain.doFilter(request ,response);   //If everything is OK then proceed to next filter/servlets (in case of multiple filters) by calling 'chain' as done here, else break the request-processing loop in your application – not doing anything or just redirecting user back due lacks logic
        }        		    		//End Session handling part   //Do note this is Servlet and JSP way but you can also make use of Spring’ Security via @Secured annotation, HttpSession management etc. It'll be a bit more complex than above simple example however it gives an idea about how security sensitive operations might look like in Java
    }       	//End doFilter method   //Same comments apply here as well for init() and destroy(). Let the Servlet world worry to itself – you’re not expected/able handling HTTP requests by yourself. Spring handles all of that so there is no need nor reason why we should be writing our own code in these parts
     @Override      public void destroy(){ }   //Do nothing here because it's only for initialization and destruction purpose which Servlet does automatically on its end – you can’t put any logic inside this method. It gets called when the web application is stopped (like JVM shuts down). No need to make changes there as servlets run indefinitely if not managed by Spring
}   //End SessionManager Class definition here, no comments added for readability purpose but just keep it simple – you’ve done all Servlet related stuff so far. Do more coding and then remember: Happy Coding! (A07_AuthFailure)